class Solution:
    def coinChange(self, coins, amount) -> int:
        if amount == 0:
            return 0;
        dp = [amount] * (amount + 1);
dp[0] = 0;
        for coin in coins:
            for i in range(coin, amount + 1):
                dp[i] = min(dp[i], dp[i - coin] + 1);
        return dp[amount] == amount ? -1 : dp[amount];
